// Process each auction with Surplus List
const items = $input.all();
const results = [];

for (const item of items) {
  const record = item.json;
  const fields = record.fields || {};

  // Verify Surplus List exists and Foreclosures is empty
  if (fields["Surplus List"] && fields["Surplus List"].length > 0 && 
      (!fields["Foreclosures"] || fields["Foreclosures"].length === 0)) {

    const timestamp = new Date().toISOString();

    results.push({
      json: {
        recordId: record.id,
        auctionName: fields["Auction Name"] || "Unknown Auction",
        county: fields["County"] ? fields["County"][0] : "Unknown County",
        surplusList: fields["Surplus List"],
        message: `Surplus List found for auction at ${timestamp}`,
        action: 'process_surplus_list'
      }
    });
  }
}

return results.length > 0 ? results : [];
